	storeOnce.Do(func() {
		storeType := os.Getenv("STORE_TYPE")
		if storeType == "" {
			storeType = "redis"
		}
		storeInstance = initStore(storeType)
	})
	return storeInstance
}

func initStore(storeType string) Store {
	switch storeType {
	case "redis":
		addr := os.Getenv("REDIS_ADDR")
		password := os.Getenv("REDIS_PASSWORD")
		required := os.Getenv("REDIS_PASSWORD_REQUIRED")
		if password == "" && required != "false" {
			return nil
		}
		return newRedisStore(addr, password)
	case "valkey":
		addr := os.Getenv("VALKEY_ADDR")
		password := os.Getenv("VALKEY_PASSWORD")
		required := os.Getenv("VALKEY_PASSWORD_REQUIRED")
		if password == "" && required != "false" {
			return nil
		}
		return newValkeyStore(addr, password)
	default:
		return newRedisStore(os.Getenv("REDIS_ADDR"), os.Getenv("REDIS_PASSWORD"))
	}
}

