	if storeType == "" {
		storeType = redisStoreType
	}

	switch storeType {
	case redisStoreType:
		addr := os.Getenv("REDIS_ADDR")
		password := os.Getenv("REDIS_PASSWORD")
		required := strings.ToLower(os.Getenv("REDIS_PASSWORD_REQUIRED"))
		if password == "" && required != "false" {
			storeInstance = nil
			return nil
		}
		storeInstance = newRedisStore(addr, password)
		return nil
