		required := strings.ToLower(os.Getenv("VALKEY_PASSWORD_REQUIRED"))
		if password == "" && required != "false" {
			storeInstance = nil
			return nil
		}
		var err error
		storeInstance, err = newValkeyStore(addr, password)
		return err
	default:
		storeInstance = newRedisStore(os.Getenv("REDIS_ADDR"), os.Getenv("REDIS_PASSWORD"))
		return nil
	}
