package store

import (
	"context"
	"encoding/json"
	"fmt"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"k8s.io/klog/v2"
)

type valkeyStore struct {
	cli                  valkey.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func newValkeyStore(addr, password string) (Store, error) {
	opt := &valkey.ClientOption{
		InitAddress: strings.Split(addr, ","),
		Password:    password,
	}

	if strings.ToLower(os.Getenv("VALKEY_DISABLE_CACHE")) == "true" {
		opt.DisableCache = true
	}
	if strings.ToLower(os.Getenv("VALKEY_FORCE_SINGLE")) == "true" {
		opt.ForceSingleClient = true
	}

	cli, err := valkey.NewClient(opt)
	if err != nil {
		return nil, fmt.Errorf("failed to create valkey client: %w", err)
	}

	return &valkeyStore{
		cli:                  cli,
		sessionPrefix:        "session:",
		expiryIndexKey:      "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}, nil
}

func (vs *valkeyStore) Ping() error {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	result := vs.cli.B().Ping().Build().Run(ctx, vs.cli)
	if result.Error() != nil {
		return result.Error()
	}
	if result.Message() != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result.Message())
	}
	return nil
}

func (vs *valkeyStore) sessionKey(sessionID string) string {
	return vs.sessionPrefix + sessionID
}

func (vs *valkeyStore) GetSandboxBySessionID(sessionID string) (*SandboxInfo, error) {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	key := vs.sessionKey(sessionID)
	result := vs.cli.B().Get().Key(key).Build()
	cmd := result.Run(ctx, vs.cli)
	if cmd.Error() != nil {
		if cmd.IsNil() {
			return nil, ErrNotFound
		}
		return nil, cmd.Error()
	}
	data, err := cmd.Bytes()
	if err != nil {
		return nil, err
	}
	var info SandboxInfo
	if err := json.Unmarshal(data, &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (vs *valkeyStore) StoreSandbox(sessionID string, info *SandboxInfo) error {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	key := vs.sessionKey(sessionID)
	data, err := json.Marshal(info)
	if err != nil {
		return err
	}

	cmds := make([]valkey.Commands, 0, 5)
	cmds = append(cmds, vs.cli.B().Setnx().Key(key).Value(string(data)).Build())
	if info.ExpiresAt > 0 {
		cmds = append(cmds, vs.cli.B().Zadd().Key(vs.expiryIndexKey).ScoreMember(&valkey.ZAddMember{
			Score:  float64(info.ExpiresAt),
			Member: sessionID,
		}).Build())
	}
	if info.LastActivity > 0 {
		cmds = append(cmds, vs.cli.B().Zadd().Key(vs.lastActivityIndexKey).ScoreMember(&valkey.ZAddMember{
			Score:  float64(info.LastActivity),
			Member: sessionID,
		}).Build())
	}

	results, err := vs.cli.DoMulti(ctx, vs.cli, cmds...)
	if err != nil {
		return err
	}
	for _, r := range results {
		if r.Error() != nil {
			return r.Error()
		}
	}
	return nil
}

func (vs *valkeyStore) UpdateSandbox(sessionID string, info *SandboxInfo) error {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	key := vs.sessionKey(sessionID)
	data, err := json.Marshal(info)
	if err != nil {
		return err
	}
	result := vs.cli.B().Set().Key(key).Value(string(data)).Nx(true).Build().Run(ctx, vs.cli)
	if result.Error() != nil {
		return result.Error()
	}
	if result.String() != "OK" {
		return fmt.Errorf("failed to update sandbox: %s", result.String())
	}
	return nil
}

func (vs *valkeyStore) DeleteSandboxBySessionID(sessionID string) error {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	key := vs.sessionKey(sessionID)
	cmds := []valkey.Commands{
		vs.cli.B().Del().Key(key).Build(),
		vs.cli.B().Zrem().Key(vs.expiryIndexKey).Members(sessionID).Build(),
		vs.cli.B().Zrem().Key(vs.lastActivityIndexKey).Members(sessionID).Build(),
	}
	results, err := vs.cli.DoMulti(ctx, vs.cli, cmds...)
	if err != nil {
		return err
	}
	for _, r := range results {
		if r.Error() != nil && !r.IsNil() {
			return r.Error()
		}
	}
	return nil
}

func (vs *valkeyStore) ListExpiredSandboxes(before int64, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	cutoff := strconv.FormatInt(before, 10)
	result := vs.cli.B().Zrangebyscore().Key(vs.expiryIndexKey).Min("-inf").Max(cutoff).Limit(0, int64(limit)).Build()
	cmd := result.Run(ctx, vs.cli)
	if cmd.Error() != nil {
		return nil, cmd.Error()
	}
	ids, err := cmd.AsStrings()
	if err != nil {
		return nil, err
	}
	return vs.loadSandboxesBySessionIDs(ctx, ids)
}

func (vs *valkeyStore) ListInactiveSandboxes(before int64, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	cutoff := strconv.FormatInt(before, 10)
	result := vs.cli.B().Zrangebyscore().Key(vs.lastActivityIndexKey).Min("-inf").Max(cutoff).Limit(0, int64(limit)).Build()
	cmd := result.Run(ctx, vs.cli)
	if cmd.Error() != nil {
		return nil, cmd.Error()
	}
	ids, err := cmd.AsStrings()
	if err != nil {
		return nil, err
	}
	return vs.loadSandboxesBySessionIDs(ctx, ids)
}

func (vs *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, ids []string) ([]*SandboxInfo, error) {
	if len(ids) == 0 {
		return []*SandboxInfo{}, nil
	}

	keys := make([]string, len(ids))
	for i, id := range ids {
		keys[i] = vs.sessionKey(id)
	}

	result := vs.cli.B().Mget().Key(keys...).Build()
	cmd := result.Run(ctx, vs.cli)
	if cmd.Error() != nil {
		return nil, cmd.Error()
	}

	values, err := cmd.AsStrings()
	if err != nil {
		return nil, err
	}

	var resultSandboxes []*SandboxInfo
	for _, data := range values {
		if data == "" {
			continue
		}
		var info SandboxInfo
		if err := json.Unmarshal([]byte(data), &info); err != nil {
			klog.V(4).Infof("failed to unmarshal sandbox: %v", err)
			continue
		}
		resultSandboxes = append(resultSandboxes, &info)
	}
	return resultSandboxes, nil
}

func (vs *valkeyStore) UpdateSessionLastActivity(sessionID string, timestamp int64) error {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	key := vs.sessionKey(sessionID)
	existsCmd := vs.cli.B().Exists().Key(key).Build()
	cmd := existsCmd.Run(ctx, vs.cli)
	if cmd.Error() != nil {
		return cmd.Error()
	}
	count, err := cmd.AsInt64()
	if err != nil {
		return err
	}
	if count == 0 {
		return ErrNotFound
	}
	result := vs.cli.B().Zadd().Key(vs.lastActivityIndexKey).ScoreMember(&valkey.ZAddMember{
		Score:  float64(timestamp),
		Member: sessionID,
	}).Build().Run(ctx, vs.cli)
	return result.Error()
}

func (vs *valkeyStore) Close() error {
	vs.cli.Close()
	return nil
}

